      out.print(cdnurl);
      out.write("/intl/common/img/feature_chart_L2.png\" alt=\"Social Collaboration Screenshot\"/>\r\n    <h1 style=\"float:left;\">Automatic Reporting</h1>\r\n    <p style=\"width:250px;float:left;\">With a powerful online analytical processing engine, you can produce many types of report without writing a line of code.</p>\r\n    <p style=\"width:250px;float:left;\">Ragic includes a analytical charting tool for you to view the trend of your latest data, along with a ranking tool to see its composition in this time period.</p>\r\n    <p style=\"width:250px;float:left;\">We also have a pivot table report for you to do more detailed analysis between the correlations of two fields of your choice.</p>\r\n    <p style=\"width:250px;float:left;\">Ragic also supports exporting your data in Excel, text or HTML.</p>\r\n  </div>\r\n\r\n  <a name=\"datalinks\"></a>\r\n  <div class=\"feature1column clearfix\" style=\"margin:50px 0 50px 20px;\">\r\n    <h1 style=\"float:left;\">Flexible Data Links</h1>\r\n    <img style=\"float:right\" class=\"feature1Img\" src=\"");
